#!/usr/bin/env python3
# AUTHORIZED LAB ONLY -- renders a vishing call script + a simulated IVR capture flow locally.
# No telephony provider is contacted; the 'caller' and 'callee' are in-process.
import json

PRETEXT = {
  'scenario': 'FAKE-IT-helpdesk-MFA-reset',
  'callee_number': '+1-555-0100 (example.test reserved range)',
  'opening': 'Hi, this is the IT service desk calling about a flagged sign-in on your account.',
  'ask': 'To verify, can you read me the 6-digit code we just sent to your phone?',
  'capture_field': 'otp',
}

def simulated_ivr(transcript):
    # Models the attacker IVR capturing an OTP the victim reads aloud.
    captured = {}
    for line in transcript:
        if line.startswith('CALLEE:'):
            digits = ''.join(c for c in line if c.isdigit())
            if len(digits) == 6:
                captured['otp'] = digits
    return captured

if __name__ == '__main__':
    print('--- VISHING CALL SCRIPT ---'); print(json.dumps(PRETEXT, indent=2))
    # Simulated call transcript (FAKE values only)
    transcript = [
        'CALLER: ' + PRETEXT['opening'],
        'CALLER: ' + PRETEXT['ask'],
        'CALLEE: sure, it is 1 2 3 4 5 6',
    ]
    print('--- SIMULATED TRANSCRIPT ---'); print('\n'.join(transcript))
    got = simulated_ivr(transcript)
    print('CAPTURED:', got)
    assert got.get('otp') == '123456'
    print('SEAM CONFIRMED: pretext drives victim to disclose OTP; capture logic recorded it')

